#include <stdio.h>
#include <stdlib.h>
int cmp_desc(const void *a, const void *b) {
    int x = *(int*)b - *(int*)a;
    return x;
}
int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N, K, L; scanf("%d %d %d", &N, &K, &L);
        int *eligible = (int*)malloc(N * sizeof(int));
        int cnt = 0;
        for (int i = 0; i < N; ++i) {
            int M, Li; scanf("%d %d", &M, &Li);
            if (Li == L) eligible[cnt++] = M;
        }
        if (cnt < K) {
            printf("-1\n");
            free(eligible);
            continue;
        }
        qsort(eligible, cnt, sizeof(int), cmp_desc);
        long long sum = 0;
        for (int i = 0; i < K; ++i) sum += eligible[i];
        printf("%lld\n", sum);
        free(eligible);
    }
    return 0;
}

