import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it)); K = int(next(it)); L = int(next(it))
        eligible = []
        for _ in range(N):
            M = int(next(it)); Li = int(next(it))
            if Li == L:
                eligible.append(M)
        if len(eligible) < K:
            out_lines.append('-1')
        else:
            eligible.sort(reverse=True)
            out_lines.append(str(sum(eligible[:K])))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

